package kr.gampa.battlegrounds.vehicle; public record VehicleState(double speedKmh,double fuel,double durability,boolean destroyed){public static VehicleState fresh(VehicleSpec s){return new VehicleState(0,s.fuelCapacity(),s.durability(),false);}public VehicleState damage(double amount){double left=Math.max(0,durability-Math.max(0,amount));return new VehicleState(speedKmh,fuel,left,left<=0);}public VehicleState refuel(double amount,double capacity){return new VehicleState(speedKmh,Math.min(capacity,fuel+Math.max(0,amount)),durability,destroyed);}}